package com.treeeducation.ioas.report; import com.treeeducation.ioas.common.ApiResponse;import com.treeeducation.ioas.media.assetfile.*;import com.treeeducation.ioas.media.contentpackage.ContentPackageRepository;import com.treeeducation.ioas.lead.LeadRepository;import com.treeeducation.ioas.task.*;import io.swagger.v3.oas.annotations.*;import io.swagger.v3.oas.annotations.tags.Tag;import org.springframework.data.domain.PageRequest;import org.springframework.web.bind.annotation.*; /** Real-data report APIs; frontend must not derive core business metrics itself. */ @RestController @RequestMapping("/api/v1/reports") @Tag(name="Report",description="媒体产出报表与运营线索报表") public class ReportController{private final ContentPackageRepository packages;private final AssetFileRepository files;private final LeadRepository leads;private final TaskRepository tasks; public ReportController(ContentPackageRepository packages,AssetFileRepository files,LeadRepository leads,TaskRepository tasks){this.packages=packages;this.files=files;this.leads=leads;this.tasks=tasks;} @GetMapping("/media-output") @Operation(summary="媒体产出报表") public ApiResponse<ReportDtos.MediaOutput> media(){var all=files.findByIsDeletedFalse(PageRequest.of(0,100000)).getContent();return ApiResponse.ok(new ReportDtos.MediaOutput(packages.count(),all.stream().filter(f->f.getType()==AssetFileType.script).count(),all.stream().filter(f->f.getType()==AssetFileType.video).count(),all.stream().filter(f->f.getType()==AssetFileType.image).count()));} @GetMapping("/operator-leads") @Operation(summary="运营线索报表") public ApiResponse<ReportDtos.OperatorLead> operator(){return ApiResponse.ok(new ReportDtos.OperatorLead(leads.count(),tasks.countByTypeAndStatus(TaskType.operator,TaskStatus.completed),tasks.countByTypeAndStatus(TaskType.operator,TaskStatus.pending)));}}
